class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length / 2;
        int[] couple = new int[n];
        for (int i = 0; i < n; i++) {
            couple[i] = row[2 * i];
        }
        int res = 0;
        for (int i = 0; i < n; i++) {
            if (couple[i] != row[2 * i]) {
                int j = find(couple, row[2 * i]);
                swap(couple, i, j);
                res++;
            }
        }
        return res;
    }

    private void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }

    private int find(int[] arr, int target) {
        for (int i = 0; i < arr.length; i++) {
            if (arr[i] == target) {
                return i;
            }
        }
        return -1;
    }
}
